     1вҶ’// FreeLang v2 - C Compiler bridge
     2вҶ’// Calls GCC, returns structured result. No human output.
     3вҶ’
     4вҶ’import { execSync } from 'child_process';
     5вҶ’import { writeFileSync, unlinkSync, existsSync, mkdirSync } from 'fs';
     6вҶ’import { join } from 'path';
     7вҶ’import { CompileResult } from './types';
     8вҶ’
     9вҶ’const OUT_DIR = join(process.cwd(), '.freelang-ai-out');
    10вҶ’
    11вҶ’export class Compiler {
    12вҶ’  private outDir: string;
    13вҶ’
    14вҶ’  constructor(outDir?: string) {
    15вҶ’    this.outDir = outDir ?? OUT_DIR;
    16вҶ’    if (!existsSync(this.outDir)) {
    17вҶ’      mkdirSync(this.outDir, { recursive: true });
    18вҶ’    }
    19вҶ’  }
    20вҶ’
    21вҶ’  compile(cCode: string, name: string): CompileResult {
    22вҶ’    const cPath = join(this.outDir, `${name}.c`);
    23вҶ’    const binPath = join(this.outDir, name);
    24вҶ’
    25вҶ’    try {
    26вҶ’      writeFileSync(cPath, cCode);
    27вҶ’      const output = execSync(`gcc -O2 -o "${binPath}" "${cPath}" -lm 2>&1`, {
    28вҶ’        encoding: 'utf-8',
    29вҶ’        timeout: 10_000,
    30вҶ’      });
    31вҶ’      return { ok: true, c_code: cCode, binary_path: binPath, gcc_output: output };
    32вҶ’    } catch (e: unknown) {
    33вҶ’      const msg = e instanceof Error ? (e as any).stderr ?? e.message : String(e);
    34вҶ’      return { ok: false, c_code: cCode, error: msg };
    35вҶ’    }
    36вҶ’  }
    37вҶ’
    38вҶ’  run(binPath: string): { ok: boolean; stdout: string; exit_code: number } {
    39вҶ’    try {
    40вҶ’      const stdout = execSync(`"${binPath}"`, { encoding: 'utf-8', timeout: 5_000 });
    41вҶ’      return { ok: true, stdout: stdout.trim(), exit_code: 0 };
    42вҶ’    } catch (e: unknown) {
    43вҶ’      const err = e as any;
    44вҶ’      return { ok: false, stdout: err.stdout ?? '', exit_code: err.status ?? 1 };
    45вҶ’    }
    46вҶ’  }
    47вҶ’
    48вҶ’  compileAndRun(cCode: string, name: string): { compile: CompileResult; run?: { ok: boolean; stdout: string; exit_code: number } } {
    49вҶ’    const cr = this.compile(cCode, name);
    50вҶ’    if (!cr.ok || !cr.binary_path) return { compile: cr };
    51вҶ’    const rr = this.run(cr.binary_path);
    52вҶ’    return { compile: cr, run: rr };
    53вҶ’  }
    54вҶ’
    55вҶ’  cleanup(name: string): void {
    56вҶ’    const cPath = join(this.outDir, `${name}.c`);
    57вҶ’    const binPath = join(this.outDir, name);
    58вҶ’    try { if (existsSync(cPath)) unlinkSync(cPath); } catch { /* ignore */ }
    59вҶ’    try { if (existsSync(binPath)) unlinkSync(binPath); } catch { /* ignore */ }
    60вҶ’  }
    61вҶ’}
