interface ValidatedFailedLogic {
  type: string;
  severity: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW';
  timestamp: number;
}

constructor(failedLogicPath: string = './failed_logic.log') {
  try {
    const content = fs.readFileSync(failedLogicPath, 'utf-8');
    const parsed = JSON.parse(content);

    // Schema validation
    if (!Array.isArray(parsed.failed_logic)) {
      throw new Error('Invalid format');
    }

    this.failedLogic = parsed.failed_logic
      .filter(item => this.validateLogicEntry(item))
      .map(item => ({
        type: String(item.type).substring(0, 255),
        severity: item.severity || 'MEDIUM',
        timestamp: Number(item.timestamp) || Date.now()
      }));
  } catch (e) {
    this.failedLogic = [];
  }
}
```

