  /**
   * Validate and sanitize filename
   * Only allows alphanumeric, dash, underscore
   */
  private sanitizeIdentifier(name: string): string {
    if (!name || name.length === 0) {
      throw new Error('Empty identifier');
    }

    if (name.length > MAX_IDENTIFIER_LENGTH) {
      throw new Error(`Identifier too long (max ${MAX_IDENTIFIER_LENGTH})`);
    }

    // Reject path traversal attempts
    if (name.includes('..') || name.includes('/') || name.includes('\\')) {
      throw new Error('Invalid identifier: contains path separators');
    }

    // Only allow [a-zA-Z0-9_-]
    if (!/^[a-zA-Z0-9_-]+$/.test(name)) {
      throw new Error('Invalid identifier: contains forbidden characters');
    }

    return name;
  }

  /**
   * Compile C code using spawnSync (safe process execution)
   */
  compile(cCode: string, name: string): CompileResult {
    try {
      // вң… SECURE: Input validation
      const safeName = this.sanitizeIdentifier(name);
      const cPath = join(this.outDir, `${safeName}.c`);
      const binPath = join(this.outDir, safeName);

      // вң… SECURE: Write validated code
      writeFileSync(cPath, cCode);

      // вң… SECURE: Use spawnSync with argument array (NO shell interpretation)
      const result = spawnSync('gcc', [
        '-O2',
        '-o', binPath,
        cPath,
        '-lm'
      ], {
        encoding: 'utf-8',
        timeout: 10_000,
        maxBuffer: 10 * 1024 * 1024,
        stdio: ['pipe', 'pipe', 'pipe']  // Prevent stdin/stdout/stderr conflicts
      });

      if (result.error) {
        return {
          ok: false,
          c_code: cCode,
          error: `GCC execution failed: ${result.error.message}`
        };
      }

      if (result.status !== 0) {
        return {
          ok: false,
          c_code: cCode,
          error: result.stderr || `GCC exit code: ${result.status}`
        };
      }

      return {
        ok: true,
        c_code: cCode,
        binary_path: binPath,
        gcc_output: result.stdout || ''
      };
    } catch (error) {
      return {
        ok: false,
        c_code: cCode,
        error: error instanceof Error ? error.message : String(error)
      };
    }
  }

  /**
   * Execute compiled binary safely
   */
  run(binPath: string): { ok: boolean; stdout: string; exit_code: number } {
    try {
      // вң… SECURE: Validate path
      if (!binPath || !binPath.startsWith(this.outDir)) {
        return {
          ok: false,
          stdout: '',
          exit_code: 1
        };
      }

      if (!existsSync(binPath)) {
        return {
          ok: false,
          stdout: `Binary not found: ${binPath}`,
          exit_code: 1
        };
      }

      // вң… SECURE: Use spawnSync with direct path (NO shell)
