### Fixed Code

```typescript
// src/compiler/self-critical-compiler.ts (SECURE)
import * as fs from 'fs';
import { z } from 'zod';

// вң… SECURE: Define strict schema
const FailedLogicEntrySchema = z.object({
  type: z.string().max(255).min(1),
  severity: z.enum(['CRITICAL', 'HIGH', 'MEDIUM', 'LOW']).default('MEDIUM'),
  timestamp: z.number().int().positive().default(() => Date.now()),
  successRate: z.number().min(0).max(1).optional(),
  count: z.number().int().nonnegative().optional()
});

const FailedLogicSchema = z.object({
  failed_logic: z.array(FailedLogicEntrySchema).max(10000)  // Max 10k entries
}).strict();  // Reject unknown properties

type FailedLogicEntry = z.infer<typeof FailedLogicEntrySchema>;
type FailedLogic = z.infer<typeof FailedLogicSchema>;

export class SelfCriticalCompiler {
  private failedLogic: FailedLogic | null = null;
  private readonly maxFileSize = 50 * 1024 * 1024;  // 50MB limit

  constructor(failedLogicPath: string = './failed_logic.log') {
    try {
      // вң… SECURE: Check file size before reading
      if (!fs.existsSync(failedLogicPath)) {
        this.failedLogic = null;
        return;
      }

      const stats = fs.statSync(failedLogicPath);
      if (stats.size > this.maxFileSize) {
        throw new Error(`File too large: ${stats.size} bytes`);
      }

      const content = fs.readFileSync(failedLogicPath, 'utf-8');

      // вң… SECURE: Parse with schema validation
      const parsed = JSON.parse(content);
      this.failedLogic = FailedLogicSchema.parse(parsed);
    } catch (error) {
      // Log error but don't crash
      console.error('Failed to load failed_logic.log:', error instanceof Error ? error.message : String(error));
      this.failedLogic = null;
    }
  }

  /**
   * Calculate probability with type-safe operations
   */
  calculateProbability(fix: Fix, errorPattern: string): number {
    if (!this.failedLogic || this.failedLogic.failed_logic.length === 0) {
      return this.getBaseProbability(fix.severity);
    }

    // вң… SECURE: Type-safe filtering and matching
    const similarCases: FailedLogicEntry[] = this.failedLogic.failed_logic.filter(
      (logic: FailedLogicEntry) => {
        // Validate type before using
        if (typeof logic.type !== 'string') return false;
        return logic.type.includes(errorPattern);
      }
    );

    if (similarCases.length === 0) {
      return this.getBaseProbability(fix.severity);
    }

    const baseProb = this.getBaseProbability(fix.severity);
    const historicalSuccess = this.getHistoricalSuccessRate(similarCases);

    // Clamp result to [0, 1]
    return Math.min(1, Math.max(0, baseProb * 0.6 + historicalSuccess * 0.4));
  }

  private getBaseProbability(severity: string): number {
    switch (severity) {
      case 'CRITICAL': return 0.70;
      case 'HIGH': return 0.60;
      case 'MEDIUM': return 0.50;
      case 'LOW': return 0.40;
      default: return 0.50;
    }
  }

  private getHistoricalSuccessRate(cases: FailedLogicEntry[]): number {
    if (cases.length === 0) return 0.5;

    const total = cases.reduce((sum, c) => sum + (c.successRate || 0.5), 0);
    return total / cases.length;
  }
}
