  private readonly maxRetries = 3;

  /**
   * вң… SECURE: Search with argument array
   */
  async search(query: string, limit: number = 20): Promise<KPMSearchResult[]> {
    try {
      // Validate inputs
      if (!query || typeof query !== 'string' || query.length > 1000) {
        throw new Error('Invalid query');
      }
      if (!Number.isInteger(limit) || limit < 1 || limit > 1000) {
        throw new Error('Invalid limit');
      }

      // вң… SECURE: Use argument array, not shell string
      const result = await this.executeCommand(['search', query, '--limit', String(limit)]);
      return this.parseSearchResults(result);
    } catch (error) {
      console.error(`KPM search failed for "${query}":`, error instanceof Error ? error.message : error);
      return [];
    }
  }

  /**
   * вң… SECURE: Info with argument array
   */
  async info(packageName: string): Promise<any> {
    try {
      this.validatePackageName(packageName);
      const result = await this.executeCommand(['info', packageName]);
      return this.parseInfoResult(result);
    } catch (error) {
      console.error(`KPM info failed for "${packageName}":`, error instanceof Error ? error.message : error);
      return null;
    }
  }

  /**
   * вң… SECURE: Install with argument array
   */
  async install(packageName: string, options: InstallOptions = {}): Promise<boolean> {
    try {
      this.validatePackageName(packageName);

      // вң… SECURE: Build argument array instead of string
      const args: string[] = ['install', packageName];

      if (options.version) {
        this.validateVersion(options.version);
        args.push(`@${options.version}`);
      }

      if (options.force) {
        args.push('--force');
      }

      if (options.offline) {
        args.push('--offline');
      }

      const result = await this.executeCommand(args);
      return this.parseSuccess(result);
    } catch (error) {
      console.error(`KPM install failed for "${packageName}":`, error instanceof Error ? error.message : error);
      return false;
    }
  }

  /**
   * вң… SECURE: Uninstall with argument array
   */
  async uninstall(packageName: string): Promise<boolean> {
    try {
      this.validatePackageName(packageName);
      const result = await this.executeCommand(['uninstall', packageName]);
      return this.parseSuccess(result);
    } catch (error) {
      console.error(`KPM uninstall failed for "${packageName}":`, error instanceof Error ? error.message : error);
      return false;
    }
  }

  /**
   * вң… SECURE: Execute command with argument array (NO SHELL)
   */
  private async executeCommand(args: string[]): Promise<string> {
    let lastError: Error | null = null;

    for (let attempt = 0; attempt < this.maxRetries; attempt++) {
      try {
        // вң… SECURE: Use execFile with argument array, NO shell interpretation
        const { stdout, stderr } = await execFileAsync('node', [this.kpmBinary, ...args], {
          timeout: this.timeout,
          maxBuffer: 10 * 1024 * 1024,
          shell: false  // Explicitly disable shell
        });

        if (stderr && stderr.length > 0) {
          throw new Error(`KPM error: ${stderr}`);
        }

        return stdout;
      } catch (error) {
        lastError = error as Error;

        // Don't retry on specific errors
        if (error instanceof Error && error.message.includes('not found')) {
          throw error;
        }

        // Wait before retry (exponential backoff)
        if (attempt < this.maxRetries - 1) {
          await this.delay(1000 * (attempt + 1));
        }
      }
    }

    throw lastError || new Error('KPM command failed after retries');
  }

  /**
   * вң… SECURE: Input validation
   */
  private validatePackageName(name: string): void {
    if (!name || typeof name !== 'string') {
      throw new Error('Invalid package name');
    }

    if (name.length > 214) {  // NPM limit
      throw new Error('Package name too long');
    }

    // Whitelist allowed characters
    if (!/^(@[a-z0-9-]+\/)?[a-z0-9-]+$/.test(name)) {
      throw new Error('Invalid package name format');
    }
  }

  private validateVersion(version: string): void {
    if (!version || typeof version !== 'string' || version.length > 50) {
      throw new Error('Invalid version');
    }

    // Basic semver validation
    if (!/^\d+\.\d+\.\d+$/.test(version)) {
      throw new Error('Invalid version format');
    }
  }

  private delay(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  private parseSearchResults(result: string): KPMSearchResult[] {
    try {
      const parsed = JSON.parse(result);
      if (!Array.isArray(parsed)) return [];
      return parsed.filter(item => item.name && item.version);
    } catch {
      return [];
    }
  }

  private parseInfoResult(result: string): any {
    try {
      return JSON.parse(result);
    } catch {
      return null;
    }
  }

  private parseSuccess(result: string): boolean {
    try {
      const parsed = JSON.parse(result);
      return parsed.success === true;
    } catch {
      return false;
    }
  }
}
