## 4. FIX: Integer Overflow in Query Parameters

### Original Vulnerable Code

```typescript
// src/api/alerts-api.ts (VULNERABLE)
private handleGetRecords(req: Request, res: Response): void {
  try {
    // рҹ”ҙ VULNERABLE: No range validation
    const limit = parseInt(req.query.limit as string) || 50;
    const records = this.alertManager.getRecords(limit);  // Could be 2^31-1

    res.json({
      success: true,
      count: records.length,
      records
    });
  } catch (error) {
    res.status(500).json({ error: String(error) });
  }
}
```

### Fixed Code

```typescript
// src/api/alerts-api.ts (SECURE)
import { z } from 'zod';

// вң… SECURE: Define constraints
const QueryLimitSchema = z.object({
  limit: z.string()
    .optional()
    .transform(v => v ? parseInt(v, 10) : 50)
    .refine(v => Number.isInteger(v), 'Must be integer')
    .refine(v => v > 0, 'Must be positive')
    .refine(v => v <= 1000, 'Maximum 1000 records')
    .default(50)
});

private handleGetRecords(req: Request, res: Response): void {
  try {
    // вң… SECURE: Validate and constrain input
    const validation = QueryLimitSchema.safeParse({ limit: req.query.limit });

    if (!validation.success) {
      res.status(400).json({
        error: 'Invalid query parameters',
        details: validation.error.errors
      });
      return;
    }

    const limit = validation.data.limit;  // Now type-safe and validated
    const records = this.alertManager.getRecords(limit);

    res.json({
      success: true,
      count: records.length,
      records
    });
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
}
