## 5. FIX: Prototype Pollution

### Original Vulnerable Code

```typescript
// src/phase-20/codegen-base/code-generator-base.ts (VULNERABLE)
export class CodeGeneratorBase {
  protected config: GeneratorConfig;

  updateConfig(config: Partial<GeneratorConfig>): void {
    // рҹ”ҙ VULNERABLE: Untrusted object merged directly
    Object.assign(this.config, config);
  }
}
