### Fixed Code

```typescript
// src/phase-20/codegen-base/code-generator-base.ts (SECURE)
export class CodeGeneratorBase {
  protected config: GeneratorConfig;

  /**
   * вң… SECURE: Safe object merging
   */
  updateConfig(config: any): void {
    if (!config || typeof config !== 'object' || Array.isArray(config)) {
      throw new Error('Invalid config');
    }

    // вң… SECURE: Only copy whitelisted properties
    const ALLOWED_KEYS = ['debug', 'optimization', 'timeout', 'maxMemory'];

    for (const key of ALLOWED_KEYS) {
      if (key in config) {
        this.config[key as keyof GeneratorConfig] = config[key];
      }
    }
  }

  /**
   * вң… SECURE: Alternative using Object.create(null)
   */
  private safeAssign(target: any, source: any): void {
    if (!source || typeof source !== 'object') return;

    for (const key of Object.keys(source)) {
      // вң… SECURE: Reject dangerous prototype keys
      if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
        continue;
      }

      // Only copy own properties
      if (Object.prototype.hasOwnProperty.call(source, key)) {
        target[key] = source[key];
      }
    }
  }
}
